Here's an enhanced version that properly handles heading hierarchy and maintains content order in both HTML and text formats:

```python
import os
import requests
from playwright.sync_api import sync_playwright
from datetime import datetime
from bs4 import BeautifulSoup

def save_wechat_article(url):
    timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
    output_dir = f"WeChat_Article_{timestamp}"
    os.makedirs(output_dir, exist_ok=True)

    with sync_playwright() as p:
        browser = p.chromium.launch(headless=True)
        page = browser.new_page()

        try:
            page.goto(url, timeout=60000)
            page.wait_for_selector('#js_content', timeout=30000)

            # Extract components
            main_title = page.query_selector('.rich_media_title').inner_text().strip()
            author = page.query_selector('.rich_media_meta_list').inner_text().strip()
            content_html = page.query_selector('#js_content').inner_html()

            # Process HTML headings and structure
            soup = BeautifulSoup(content_html, 'html.parser')
            text_content = []
            image_count = 0

            # Convert WeChat headings to proper HTML tags
            for element in soup.find_all(class_=True):
                classes = element.get('class', [])

                # Detect heading levels (adjust based on actual WeChat classes)
                if 'en_title' in classes:  # Main subtitle
                    element.name = 'h2'
                elif 'section_title' in classes:  # Section heading
                    element.name = 'h3'
                elif 'rich_media_sub_title' in classes:  # Subtitle
                    element.name = 'h4'

            # Process images and build text content
            for img in soup.find_all('img'):
                src = img.get('src')
                if src and src.startswith('http'):
                    image_count += 1
                    ext = src.split('.')[-1].split('?')[0]
                    img_name = f'image_{image_count}.{ext}'
                    img_path = os.path.join(output_dir, img_name)

                    # Download image
                    with open(img_path, 'wb') as f:
                        f.write(requests.get(src).content)

                    # Replace source in HTML
                    img['src'] = img_name

                    # Add image marker to text content
                    if img.parent.name == 'p':
                        img.insert_after(f'\n[Image {image_count}] ')
                    text_content.append(f'\n[Image {image_count}]\n')

                # Remove empty paragraphs
                if not img.parent.text.strip():
                    img.parent.decompose()

            # Build structured text content
            for element in soup.find_all(True):
                if element.name in ['h2', 'h3', 'h4']:
                    text = element.get_text().strip()
                    level = int(element.name[1])
                    text_content.append(f'\n{"#" * level} {text}\n')
                elif element.name == 'p':
                    text_content.append(element.get_text().strip())
                elif element.name == 'br':
                    text_content.append('\n')

            # Create styled HTML
            html_content = f"""<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>{main_title}</title>
    <style>
        /* Main title style */
        .article-title {{
            font-size: 2.5em;
            font-weight: 700;
            margin: 1em 0;
            color: #1a1a1a;
        }}

        /* Heading hierarchy */
        h2 {{
            font-size: 1.8em;
            color: #2d2d2d;
            margin: 2em 0 1em;
            border-bottom: 2px solid #eee;
            padding-bottom: 0.5em;
        }}

        h3 {{
            font-size: 1.5em;
            color: #3d3d3d;
            margin: 1.5em 0 0.8em;
        }}

        h4 {{
            font-size: 1.3em;
            color: #4d4d4d;
            margin: 1.2em 0 0.6em;
        }}

        /* Paragraph styling */
        .content p {{
            line-height: 1.8;
            margin: 1em 0;
            font-size: 1.1em;
            color: #444;
        }}

        /* Image styling */
        img {{
            max-width: 100%;
            height: auto;
            margin: 1.5em 0;
            border-radius: 8px;
            box-shadow: 0 2px 8px rgba(0,0,0,0.1);
        }}
    </style>
</head>
<body>
    <h1 class="article-title">{main_title}</h1>
    <div class="article-meta">
        <p>Author: {author}</p>
        <p>Original URL: <a href="{url}">{url}</a></p>
        <p>Archived at: {datetime.now().strftime("%Y-%m-%d %H:%M:%S")}</p>
    </div>
    <div class="content">
        {soup.prettify()}
    </div>
</body>
</html>"""

            # Save files
            html_path = os.path.join(output_dir, 'article.html')
            with open(html_path, 'w', encoding='utf-8') as f:
                f.write(html_content)

            text_path = os.path.join(output_dir, 'structured_content.txt')
            with open(text_path, 'w', encoding='utf-8') as f:
                f.write(f"Title: {main_title}\n")
                f.write(f"Author: {author}\n\n")
                f.write('\n'.join([t for t in text_content if t.strip()]))

            print(f"✅ Article saved with proper headings in: {output_dir}")
            return html_path

        except Exception as e:
            print(f"❌ Error: {str(e)}")
            return None
        finally:
            browser.close()

# Usage
article_url = input("Enter WeChat article URL: ")
result = save_wechat_article(article_url)
```

Key improvements:
1. **Heading Hierarchy**:
   - Converts WeChat's specific classes to proper HTML heading tags (h2-h4)
   - Adds CSS styling with clear visual hierarchy
   - Maintains heading structure in both HTML and text files

2. **Structured Text File**:
   - Preserves content order (headings, paragraphs, images)
   - Marks images with [Image X] placeholders
   - Uses Markdown-style # symbols for heading levels

3. **Enhanced Formatting**:
   - Proper spacing between elements
   - Clean typography with consistent margins
   - Shadow effects on images
   - Removal of empty paragraphs

4. **Image Handling**:
   - Numbers images sequentially
   - Preserves image positions in text
   - Adds alt text placeholders

To use:
1. Install BeautifulSoup: `pip install beautifulsoup4`
2. Run the script and input a WeChat URL
3. Check both the HTML and TXT files in the output folder

The HTML will now show:
- Main title as h1 (page title + styled heading)
- Subtitles as h2 with border-bottom
- Section headings as h3
- Sub-sections as h4
- Proper spacing between all elements

The text file will show:
```
## Main Subtitle
Paragraph text
[Image 1]
### Section Heading
More text...
```

